"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[170],{9305:function(i,e,n){n.d(e,{Z:function(){return l}});var a=n(7437),r=n(7648),t=n(9376);function l(i){let{slug:e,title:n,excerpt:l,description:s,icon:o}=i,u=(0,t.usePathname)(),g=(null==u?void 0:u.startsWith("/en"))||!1;return(0,a.jsx)(r.default,{href:g?"/en/hizmetler/".concat(e):"/hizmetler/".concat(e),className:"block h-full",children:(0,a.jsxs)("div",{className:"card h-full flex flex-col items-center justify-between text-center p-6 min-h-[280px] transition-all hover:shadow-lg hover:-translate-y-1",children:[(0,a.jsx)("div",{className:"text-5xl mb-4",children:o}),(0,a.jsx)("h3",{className:"text-xl font-bold text-navy-800",children:n}),(0,a.jsx)("p",{className:"text-gray-600 text-sm mt-2 line-clamp-3",children:l}),(0,a.jsx)("p",{className:"text-gold-500 text-sm font-semibold mt-4 inline-flex items-center gap-1",children:g?"More details →":"Detaylı bilgi →"})]})})}},4944:function(i,e,n){n.d(e,{u:function(){return a}});let a={tr:[{slug:"gemi-donatim",title:"Gemi Donatım",excerpt:"Yeni inşa ve mevcut gemiler i\xe7in g\xfcvenlik, konfor ve operasyon odaklı donatım \xe7\xf6z\xfcmleri.",description:"Makine dairesi, g\xfcverte, k\xf6pr\xfc\xfcst\xfc ve yaşam alanları i\xe7in her t\xfcrl\xfc donanım. Sertifikalı \xfcr\xfcnler, hızlı tedarik, teknik danışmanlık.",content:'\n      <h2>Gemi Donatım \xc7\xf6z\xfcmlerimiz</h2>\n      <p>Sierra Marine olarak, yeni inşa edilen gemilerden mevcut filolara kadar geniş bir yelpazede <strong>gemi donatım hizmeti</strong> sunuyoruz. Amacımız, geminizin operasyonel verimliliğini artırmak, g\xfcvenlik standartlarını en \xfcst seviyede tutmak ve konforlu bir \xe7alışma ortamı sağlamaktır.</p>\n      \n      <h3>Kapsamlı \xdcr\xfcn Yelpazemiz</h3>\n      <ul>\n        <li><strong>Can kurtarma ekipmanları:</strong> SOLAS onaylı can salları (6-25 kişilik), can yelekleri (100N, 150N, 275N, bebek/\xe7ocuk), hidrostatik kilitler, halat atar sistemleri, can simitleri (2.5kg, 4kg, ışıklı), işaret fişekleri ve parakete ışıkları.</li>\n        <li><strong>Yangınla m\xfccadele sistemleri:</strong> Yangın hortumları (\xe7eşitli \xe7aplar), nozullar, Storz, Makama, İngiliz, Rus ve ABD tipi bağlantı par\xe7aları, yangın dolapları, portatif s\xf6nd\xfcr\xfcc\xfcler (karbondioksit, k\xf6p\xfck, kuru kimyevi).</li>\n        <li><strong>Boru ve havalandırma işaretlemeleri:</strong> ISO 14726\'ya uygun akış okları, tehlike sembolleri, boru etiketleri ve renk kodları (su, yakıt, hava, kimyasallar).</li>\n        <li><strong>Pilot ve embarkasyon ekipmanları:</strong> Pilot merdivenleri (UL 1044 standardı), embarkasyon merdivenleri, manyetik tutucular, acil durum aydınlatmaları (LED\'li).</li>\n        <li><strong>K\xf6pr\xfc\xfcst\xfc donanımı:</strong> Seyir fenerleri (COLREG uyumlu), sinyal lambaları, sis d\xfcd\xfckleri, manyetik pusulalar, harita masaları ve seyir aletleri.</li>\n        <li><strong>Yaşam mahalleri donanımı:</strong> Kabin mobilyaları, aydınlatma, havalandırma, ısıtma-soğutma sistemleri.</li>\n      </ul>\n      \n      <h3>Neden Sierra Marine?</h3>\n      <p>T\xfcm \xfcr\xfcnlerimiz uluslararası klas kuruluşları (DNV, Lloyd\'s Register, Bureau Veritas, T\xfcrk Loydu) tarafından onaylıdır. Stoklarımızda s\xfcrekli bulunan yedek par\xe7alar ve hızlı lojistik ağımız sayesinde acil ihtiya\xe7larınıza anında cevap veriyoruz. Ayrıca, donatım projeleriniz i\xe7in <strong>teknik danışmanlık ve kurulum desteği</strong> de sağlıyoruz.</p>\n      \n      <img src="/services/outfittings.png" alt="Gemi Donatım" class="w-full rounded-lg my-4" />\n      <img src="/services/fittings.png" alt="Yangın Hortumu Bağlantıları" class="w-full rounded-lg my-4" />\n      <p><strong>Teklif ve bilgi i\xe7in l\xfctfen bizimle iletişime ge\xe7in.</strong> Filonuzun ihtiya\xe7larına \xf6zel \xe7\xf6z\xfcmler geliştirmekten mutluluk duyarız.</p>\n    ',icon:"⚙️",image:"/services/outfittings.png"},{slug:"emniyet-ekipmanlari",title:"Emniyet Ekipmanları",excerpt:"SOLAS ve ilgili mevzuata uygun geniş \xfcr\xfcn portf\xf6y\xfc.",description:"Can yelekleri, can salları, yangın sistemleri, kişisel koruyucu donanımlar, IMO posterleri, periyodik bakım ve sertifikasyon.",content:'\n      <h2>Emniyet Ekipmanları</h2>\n      <p>Denizde can ve mal g\xfcvenliği en \xf6ncelikli konumuzdur. Sierra Marine, <strong>SOLAS, IMO, MED</strong> ve diğer uluslararası d\xfczenlemelere tam uyumlu emniyet ekipmanlarını geminize ulaştırır. \xdcr\xfcnlerimiz d\xfczenli olarak test edilir ve sertifikalandırılır.</p>\n      \n      <h3>Başlıca Emniyet \xdcr\xfcnlerimiz</h3>\n      <ul>\n        <li><strong>Can yelekleri:</strong> Yetişkin, \xe7ocuk ve bebek modelleri, işaret ışıklı ve reflekt\xf6rl\xfc tipler. 100N, 150N ve 275N kaldırma kuvveti se\xe7enekleri. SOLAS ve ISO 12402 sertifikalı.</li>\n        <li><strong>Can simitleri:</strong> 2.5 kg ve 4 kg, ışıklı (LED), y\xfczer halatlı (30m), braketli ve hızlı a\xe7ılan modeller. IMO renk kodlarına uygun.</li>\n        <li><strong>Can salları:</strong> 6, 10, 15, 20, 25 kişilik kapasitelerde, SOLAS A paket, otomatik şişme, hidrostatik salma tertibatlı.</li>\n        <li><strong>Kimyasal koruyucu giysiler:</strong> Tip 1 (tam korumalı) tulumlar, kimyasallara dayanıklı eldiven ve \xe7izmeler, acil duş \xfcniteleri (portatif ve sabit).</li>\n        <li><strong>Petrol sızıntı m\xfcdahale kitleri:</strong> Acil durumlarda kullanılmak \xfczere portatif kitler (20L, 50L), dispersanlar ve emici malzemeler (organik, hidrofobik).</li>\n        <li><strong>Termal koruyucu giysiler (TPA):</strong> Hipotermiye karşı koruma, can salları ve can yelekleri ile birlikte kullanılır. ISO 15027 standardına uygun.</li>\n        <li><strong>IMO g\xfcvenlik posterleri ve uyarı levhaları:</strong> Gemi i\xe7i ve dışı i\xe7in yangın, acil durum, ilk yardım, yasaklama ve uyarı levhaları. T\xfcm posterler IMO kurallarına uygun olup \xe7ift dilde (TR/EN) mevcuttur. A4, A3 ve 50x70 cm boyutlarında.</li>\n      </ul>\n      \n      <h3>Periyodik Bakım ve Sertifikasyon</h3>\n      <p>Can salları, yangın t\xfcpleri, EPIRB, SART ve diğer emniyet ekipmanlarının <strong>periyodik bakım, dolum ve sertifikasyon</strong> hizmetlerini yetkili servislerimizle ger\xe7ekleştiriyoruz. T\xfcm işlemlerinizi takip eden bir sistem kurarak, yenileme tarihlerini size hatırlatıyoruz. B\xf6ylece survey \xf6ncesi hazırlıksız yakalanmazsınız.</p>\n      \n      <img src="/services/safety.png" alt="Can Yelekleri ve Can Simitleri" class="w-full rounded-lg my-4" />\n      <img src="/services/chemical.png" alt="Kimyasal Koruyucu Ekipmanlar" class="w-full rounded-lg my-4" />\n      <img src="/services/posters.png" alt="G\xfcvenlik Posterleri" class="w-full rounded-lg my-4" />\n      <p><strong>Acil durum ekipmanlarınızın her zaman kullanıma hazır olması i\xe7in bizi arayın.</strong></p>\n    ',icon:"\uD83E\uDDBA",image:"/services/safety.png"},{slug:"basili-harita-seyir-yayinlari",title:"Basılı Harita ve Yayınlar",excerpt:"Resmi deniz haritaları, seyir talimatları, ITU yayınları ve Witherby's \xfcr\xfcnleri.",description:"UKHO, ITU, IMO ve Witherby's resmi basılı materyalleri. Notice to Mariners d\xfczeltme hizmeti, gemi k\xfct\xfcphanesi kurulumu.",content:'\n      <h2>Basılı Haritalar ve Seyir Yayınları</h2>\n      <p>G\xfcvenli seyir i\xe7in <strong>g\xfcncel ve doğru haritalar ile seyir yayınları</strong> şarttır. Sierra Marine, yetkili distrib\xfct\xf6r\xfc olduğu kurumlar aracılığıyla geminizin ihtiya\xe7 duyduğu t\xfcm basılı materyalleri temin eder. Yayınların g\xfcncellenmesi i\xe7in <strong>Notice to Mariners</strong> ve d\xfczeltme hizmetleri de sunuyoruz.</p>\n      \n      <h3>Admiralty Basılı \xdcr\xfcnler</h3>\n      <ul>\n        <li><strong>Standart Nautical Charts (SNC):</strong> D\xfcnya okyanuslarını ve denizlerini kapsayan resmi deniz haritaları. 3500\'den fazla farklı harita.</li>\n        <li><strong>Planlama Haritaları (Planning Charts):</strong> Rota planlaması i\xe7in kullanılan k\xfc\xe7\xfck \xf6l\xe7ekli haritalar (1:3.500.000 ve \xfczeri).</li>\n        <li><strong>Liman Yaklaşım Kılavuzları (Port Approach Guides):</strong> Belirli limanlara giriş/\xe7ıkış i\xe7in detaylı bilgiler, derinlikler, işaretler.</li>\n        <li><strong>Admiralty Sailing Directions (Pilot Books):</strong> D\xfcnyanın \xe7eşitli b\xf6lgeleri i\xe7in seyir talimatları, liman tanımları, akıntı ve gelgit bilgileri. 70\'ten fazla cilt.</li>\n        <li><strong>List of Lights and Fog Signals:</strong> Deniz fenerleri, şamandıralar, sis işaretleri ve diğer seyir yardımcılarının listesi (10 cilt).</li>\n        <li><strong>List of Radio Signals:</strong> Radyo istasyonları, DSC, NAVTEX, GMDSS bilgileri (6 cilt).</li>\n        <li><strong>Tide Tables (Gelgit Cetvelleri):</strong> Ana ve tali limanlar i\xe7in gelgit y\xfckseklikleri ve akıntı bilgileri (4 cilt).</li>\n        <li><strong>Nautical Almanac:</strong> G\xf6k cisimlerinin konumları, yıldız haritaları ve astronomik seyir i\xe7in gerekli veriler.</li>\n      </ul>\n      \n      <h3>Diğer Yayınlar</h3>\n      <ul>\n        <li><strong>T\xfcrk Notik Yayınları ve Haritaları:</strong> Seyir Hidrografi ve Oşinografi Dairesi tarafından yayınlanan T\xfcrk sularına ait haritalar, seyir kılavuzları, fener listeleri.</li>\n        <li><strong>IMO Yayınları:</strong> SOLAS, MARPOL, STCW, COLREG, ISPS Code, FSS Code, IBC Code gibi temel s\xf6zleşmelerin g\xfcncel metinleri ve kılavuzları.</li>\n        <li><strong>ITU Yayınları:</strong> Radyo d\xfczenlemeleri, telsiz s\xf6zl\xfcğ\xfc, uluslararası telekom\xfcnikasyon kuralları.</li>\n        <li><strong>Witherby\'s Yayınları:</strong> Denizcilik eğitim materyalleri, el kitapları, kargo elle\xe7leme kılavuzları, LNG/LPG rehberleri.</li>\n      </ul>\n      \n      <h3>Gemi K\xfct\xfcphanesi Kurulumu</h3>\n      <p>Geminizde bulunması zorunlu yayınların tam listesini \xe7ıkarıyor, eksiksiz bir gemi k\xfct\xfcphanesi oluşturuyoruz. D\xfczenli <strong>Notice to Mariners</strong> takibi ile yayınlarınızın her zaman g\xfcncel kalmasını sağlıyoruz. Ayrıca, dijital k\xfct\xfcphane y\xf6netimi i\xe7in yazılım desteği de verebiliriz.</p>\n      \n      <img src="/services/printed-charts.png" alt="Admiralty Basılı Haritalar" class="w-full rounded-lg my-4" />\n    ',icon:"\uD83D\uDDFA️",image:"/services/printed-charts.png"},{slug:"survey-hazirligi",title:"Survey Hazırlığı",excerpt:"Klas, bayrak ve liman devleti kontrolleri \xf6ncesi eksikliklerin tespiti ve tedarik desteği.",description:"Survey \xf6ncesi ihtiya\xe7 listesi, hızlı tedarik, işaretleme, dok\xfcmantasyon desteği, akredite servis ağı.",content:'\n      <h2>Survey Hazırlığı Hizmetlerimiz</h2>\n      <p>Klas, bayrak devleti veya liman devleti kontrolleri (PSC) \xf6ncesinde geminizin <strong>eksiksiz ve mevzuata uygun</strong> olması i\xe7in kapsamlı bir hazırlık s\xfcreci y\xfcr\xfct\xfcyoruz. Amacımız, s\xfcrpriz eksiklikler nedeniyle gecikme veya cezai durumlar yaşamanızı \xf6nlemektir.</p>\n      \n      <h3>Survey Hazırlık Adımları</h3>\n      <ul>\n        <li><strong>Eksiklik Tespiti (Gap Analysis):</strong> Uzman ekibimiz, geminizde mevcut durumu denetleyerek harita, yayın, emniyet ekipmanı, yangın sistemi, boru işaretlemeleri, ilk yardım malzemeleri gibi kalemlerdeki eksiklikleri liste halinde \xe7ıkarır.</li>\n        <li><strong>İhtiya\xe7 Listesi ve Teklif:</strong> Tespit edilen eksiklikler i\xe7in <strong>acil tedarik edilmesi gereken \xfcr\xfcnlerin listesi</strong> ve en uygun fiyatlı teklifler sunulur.</li>\n        <li><strong>Hızlı Tedarik:</strong> Stoklarımızdan veya acil tedarik kanallarımızdan eksik malzemeleri en kısa s\xfcrede geminize ulaştırırız (T\xfcrkiye genelinde 24-48 saat).</li>\n        <li><strong>Dok\xfcmantasyon Desteği:</strong> Survey i\xe7in gerekli sertifikalar, bakım kayıtları, eğitim belgeleri ve g\xfcncel harita/yayın listelerini hazırlamanıza yardımcı oluruz.</li>\n        <li><strong>İşaretleme ve Etiketleme:</strong> Boru hatları, havalandırma kanalları, yangın ekipmanları, acil durum ekipmanları i\xe7in ISO ve IMO standartlarında işaretlemeler yaparız. (Renk kodları, akış okları, tehlike piktogramları).</li>\n        <li><strong>Yangın ve emniyet ekipmanlarının periyodik bakımı:</strong> Yetkili servislerimizle can salları, yangın t\xfcpleri, sabit yangın s\xf6nd\xfcrme sistemleri, EPIRB, SART bakım ve sertifikasyonu.</li>\n      </ul>\n      \n      <p>Survey sonrasında da takip ve yenileme hizmetlerimizle geminizin her zaman hazır olmasını sağlıyoruz. <strong>Planlı bakım ve yenileme yaklaşımıyla ani ve maliyetli s\xfcrprizlerin \xf6n\xfcne ge\xe7iyoruz.</strong></p>\n      \n      <img src="/services/markings.png" alt="İşaretleme ve Etiketleme" class="w-full rounded-lg my-4" />\n      <img src="/services/posters.png" alt="Uyarı Posterleri" class="w-full rounded-lg my-4" />\n      <p><strong>Bir sonraki survey \xf6ncesi bize ulaşın, sizi eksiksiz ve belgeli bir şekilde denetime hazırlayalım.</strong></p>\n    ',icon:"\uD83D\uDCCB",image:"/services/markings.png"},{slug:"dijital-yayinlar",title:"Dijital Yayınlar & Haritalar",excerpt:"AVCS, ADP, ENP dijital seyir yayınları ve harita servisleri.",description:"Elcome LLC iş birliğiyle d\xfcnyanın en g\xfcncel dijital seyir \xfcr\xfcnleri. ECDIS entegrasyonu, kullanıcı eğitimi, 7/24 teknik destek.",content:'\n      <h2>Dijital Seyir \xc7\xf6z\xfcmleri</h2>\n      <p>Kağıt harita ve yayınların yerini hızla alan dijital \xe7\xf6z\xfcmler, <strong>g\xfcncellik, depolama kolaylığı ve maliyet avantajı</strong> sunar. Sierra Marine, <strong>Elcome LLC</strong> alt distrib\xfct\xf6r\xfc olarak Admiralty ve diğer lider markaların dijital \xfcr\xfcnlerini sunmaktadır.</p>\n      \n      <h3>Dijital \xdcr\xfcn Portf\xf6y\xfcm\xfcz</h3>\n      <ul>\n        <li><strong>AVCS (Admiralty Vector Chart Service):</strong> ECDIS uyumlu, s\xfcrekli g\xfcncellenen vekt\xf6r haritalar. T\xfcm d\xfcnya sularını kapsar. <strong>Haftalık g\xfcncellemeler</strong> ile en g\xfcncel veri. D\xfcnyada 20.000\'den fazla gemide kullanılıyor.</li>\n        <li><strong>ADP (Admiralty Digital Publications):</strong> Dijital seyir yayınları (Sailing Directions, List of Lights, List of Radio Signals, Tide Tables, Nautical Almanac). Tek bir aray\xfczden t\xfcm yayınlara erişim, anlık g\xfcncellemeler. Kağıt yayınlara g\xf6re %70\'e varan maliyet tasarrufu.</li>\n        <li><strong>ENP (Electronic Nautical Publications):</strong> IMO, ITU ve diğer kurumların elektronik yayınları. Kağıt israfını \xf6nler, arşivleme ve arama kolaylığı sağlar. Dijital imza ile resmi ge\xe7erlilik.</li>\n        <li><strong>ARCS (Admiralty Raster Chart Service):</strong> Raster harita servisi, geleneksel harita g\xf6r\xfcn\xfcm\xfcn\xfc dijital ortama taşır. ECDIS ve ECS sistemlerle uyumlu.</li>\n        <li><strong>IMO, ITU, Witherby\'s dijital yayınları:</strong> Uluslararası d\xfczenlemelerin ve kılavuzların g\xfcncel elektronik versiyonları. PDF, ePub, XML formatları.</li>\n      </ul>\n      \n      <h3>Avantajlarımız</h3>\n      <ul>\n        <li>7/24 g\xfcncel harita ve yayınlar – Manuel d\xfczeltme zahmeti yok.</li>\n        <li>Tek bir lisans ile filonuzdaki t\xfcm gemilerde kullanım imk\xe2nı.</li>\n        <li>Kullanıcı dostu aray\xfczler, hızlı arama ve filtreleme.</li>\n        <li>Yedekleme ve kolay taşınabilirlik (USB, DVD veya bulut).</li>\n        <li>ECDIS sistemlerinize tam entegrasyon – API desteği.</li>\n      </ul>\n      \n      <h3>Eğitim ve Destek</h3>\n      <p>Dijital seyir \xfcr\xfcnlerinin kurulumu, kullanıcı eğitimi ve teknik desteğini de sağlıyoruz. ECDIS sistemlerinize entegrasyon konusunda uzman kadromuzla yanınızdayız. Uzaktan veya gemide eğitim se\xe7enekleri mevcuttur.</p>\n      \n      <img src="/services/printed-charts.png" alt="Dijital Yayınlar" class="w-full rounded-lg my-4" />\n      <p><strong>Dijital d\xf6n\xfcş\xfcme hazır mısınız? Size en uygun paketi oluşturmak i\xe7in iletişime ge\xe7in.</strong></p>\n    ',icon:"\uD83C\uDF10",image:"/services/printed-charts.png"},{slug:"filo-yonetim",title:"Filo Y\xf6netim Desteği",excerpt:"Gemilerin yayın ve ekipman durumlarının takibi, yenileme planlaması ve raporlama.",description:"Dijital takip sistemi, otomatik hatırlatmalar, \xf6zelleştirilmiş raporlar, tedarik sipariş y\xf6netimi.",content:'\n      <h2>Filo Y\xf6netim Desteği</h2>\n      <p>Filonuzun t\xfcm belgelerini, ekipman periyotlarını ve survey tarihlerini dijital ortamda takip etmek artık \xe7ok kolay. Sierra Marine, size \xf6zel geliştirdiği <strong>web tabanlı y\xf6netim sistemi</strong> ile operasyonel y\xfck\xfcn\xfcz\xfc azaltır ve denetimlere her zaman hazır olmanızı sağlar.</p>\n      \n      <h3>Hizmetlerimiz</h3>\n      <ul>\n        <li><strong>Harita ve yayın listelerinin merkezi takibi:</strong> Her gemi i\xe7in g\xfcncel harita ve yayın listelerini tutar, eksiklikleri ve g\xfcncelleme ihtiyacını otomatik raporlar. Notice to Mariners takibi entegredir.</li>\n        <li><strong>Emniyet ekipmanları yenileme hatırlatma:</strong> Can salı, yangın t\xfcp\xfc, EPIRB, SART, acil durum pilleri, hidrostatik kilitler gibi ekipmanların periyodik bakım ve yenileme tarihlerini takip eder, s\xfcresi yaklaşanlar i\xe7in e-posta ve SMS bildirimi g\xf6nderir.</li>\n        <li><strong>Klas, bayrak ve PSC eksiklik raporlarının y\xf6netimi:</strong> Survey sonu\xe7larını girin, d\xfczeltme aksiyonlarını atayın, tamamlanma durumunu izleyin. Ge\xe7miş eksikliklerin analizi.</li>\n        <li><strong>Gemi \xf6zelinde ihtiya\xe7 listeleri ve tedarik siparişleri:</strong> Her gemi i\xe7in ayrı ayrı ihtiya\xe7 listesi oluşturun, siparişlerinizi tek tuşla bize iletebilirsiniz. Sipariş durumu takibi.</li>\n        <li><strong>Raporlama:</strong> Filonuzun genel durumu, uyumluluk oranları, yaklaşan survey tarihleri, en sık \xe7ıkan eksiklikler gibi konularda \xf6zelleştirilmiş raporlar (PDF, Excel, CSV).</li>\n        <li><strong>Gemi k\xfct\xfcphanesi denetimi:</strong> Periyodik olarak gemilerinizdeki yayınların g\xfcncelliğini kontrol eder, eksikleri tespit eder ve tamamlanmasını sağlar.</li>\n      </ul>\n      \n      <h3>Neden Filo Y\xf6netim Desteği?</h3>\n      <ul>\n        <li><strong>Zaman ve iş g\xfcc\xfc tasarrufu:</strong> Manuel takip zahmetinden kurtulun.</li>\n        <li><strong>Denetimlerde başarısızlık riskinin minimize edilmesi:</strong> Her zaman hazır olun.</li>\n        <li><strong>Operasyonel maliyetlerin d\xfcş\xfcr\xfclmesi:</strong> Eksiklik kaynaklı gecikmeleri ve cezaları \xf6nleyin.</li>\n        <li><strong>Merkezi kontrol:</strong> T\xfcm filonuzu tek bir panelden y\xf6netin.</li>\n      </ul>\n      \n      <img src="/services/office.png" alt="Ofis ve Y\xf6netim" class="w-full rounded-lg my-4" />\n      <p>Sistemimiz web tabanlıdır, her yerden erişilebilir ve ek bir yazılım kurulumu gerektirmez. <strong>Demo erişim talebi i\xe7in bize ulaşın.</strong></p>\n    ',icon:"⚓",image:"/services/office.png"}],en:[{slug:"gemi-donatim",title:"Marine Outfitting",excerpt:"Safety, comfort and operationally focused outfitting solutions for newbuild and existing vessels.",description:"All types of equipment for engine, deck, bridge and accommodation. Certified products, fast supply, technical consultancy.",content:'\n      <h2>Marine Outfitting Solutions</h2>\n      <p>Sierra Marine provides comprehensive outfitting services for newbuilds and existing fleets, enhancing operational efficiency, safety and comfort.</p>\n      \n      <h3>Extensive Product Range</h3>\n      <ul>\n        <li><strong>Life-saving appliances:</strong> SOLAS-approved life rafts (6-25 persons), lifejackets (100N, 150N, 275N, infant/child), hydrostatic releases, line throwing apparatus, lifebuoys (2.5kg, 4kg with light), distress signals.</li>\n        <li><strong>Fire-fighting systems:</strong> Fire hoses, nozzles, Storz, Makama, UK, US, Russian type couplings, fire cabinets, portable extinguishers (CO2, foam, dry chemical).</li>\n        <li><strong>Pipe and ventilation markings:</strong> Flow arrows, hazard symbols, pipe labels, colour coding according to ISO 14726 (water, fuel, air, chemicals).</li>\n        <li><strong>Pilot and embarkation equipment:</strong> Pilot ladders (UL 1044 standard), embarkation ladders, magnetic holders, emergency lighting (LED).</li>\n        <li><strong>Bridge equipment:</strong> Navigation lights (COLREG compliant), signal lamps, fog horns, magnetic compasses, chart tables, navigation instruments.</li>\n        <li><strong>Accommodation outfitting:</strong> Cabin furniture, lighting, ventilation, heating/cooling systems.</li>\n      </ul>\n      \n      <h3>Why Sierra Marine?</h3>\n      <p>All products are certified by major classification societies (DNV, Lloyd\'s Register, Bureau Veritas, T\xfcrk Loydu). Our extensive stock and fast logistics network ensure rapid delivery. We also provide technical consultancy and installation support for outfitting projects.</p>\n      \n      <img src="/services/outfittings.png" alt="Marine Outfitting" class="w-full rounded-lg my-4" />\n      <img src="/services/fittings.png" alt="Fire Hose Couplings" class="w-full rounded-lg my-4" />\n      <p><strong>Contact us for quotations and tailored solutions for your fleet.</strong></p>\n    ',icon:"⚙️",image:"/services/outfittings.png"},{slug:"emniyet-ekipmanlari",title:"Safety Equipment",excerpt:"Wide range of SOLAS-compliant safety equipment for crew and vessel safety.",description:"Lifejackets, life rafts, fire systems, PPE, IMO posters, periodic maintenance and certification.",content:'\n      <h2>Safety Equipment</h2>\n      <p>Safety of life at sea is our top priority. Sierra Marine supplies SOLAS, IMO, MED and other international regulations compliant safety equipment, all regularly tested and certified.</p>\n      \n      <h3>Main Safety Products</h3>\n      <ul>\n        <li><strong>Lifejackets:</strong> Adult, child and infant models, with lights and reflectors, 100N, 150N, 275N buoyancy options. SOLAS and ISO 12402 certified.</li>\n        <li><strong>Lifebuoys:</strong> 2.5kg and 4kg, with LED light, floating line (30m), bracket and quick release. IMO colour coding.</li>\n        <li><strong>Life rafts:</strong> Capacities 6, 10, 15, 20, 25 persons, SOLAS A pack, automatic inflation, hydrostatic release.</li>\n        <li><strong>Chemical protective suits:</strong> Type 1 fully encapsulated suits, chemical-resistant gloves and boots, emergency showers (portable and fixed).</li>\n        <li><strong>Oil spill response kits:</strong> Portable kits (20L, 50L), dispersants, absorbent materials (organic, hydrophobic).</li>\n        <li><strong>Thermal protective aids (TPA):</strong> Hypothermia protection, used with life rafts and lifejackets. ISO 15027 compliant.</li>\n        <li><strong>IMO safety posters and warning signs:</strong> Fire, emergency, first aid, prohibition, warning signs for interior and exterior use. All posters comply with IMO regulations and are available in dual language (TR/EN). Sizes A4, A3, 50x70 cm.</li>\n      </ul>\n      \n      <h3>Periodic Maintenance and Certification</h3>\n      <p>We provide periodic maintenance, refilling and certification services for life rafts, fire extinguishers, EPIRB, SART and other safety equipment through our authorised service centres. Our tracking system reminds you of renewal dates, ensuring you are never caught unprepared before a survey.</p>\n      \n      <img src="/services/safety.png" alt="Lifejackets and Lifebuoys" class="w-full rounded-lg my-4" />\n      <img src="/services/chemical.png" alt="Chemical Protective Suits" class="w-full rounded-lg my-4" />\n      <img src="/services/posters.png" alt="Safety Posters" class="w-full rounded-lg my-4" />\n      <p><strong>Call us to keep your emergency equipment always ready for use.</strong></p>\n    ',icon:"\uD83E\uDDBA",image:"/services/safety.png"},{slug:"basili-harita-seyir-yayinlari",title:"Printed Charts & Publications",excerpt:"Official nautical charts, sailing directions, ITU publications and Witherby's products.",description:"Official printed materials from UKHO, ITU, IMO and Witherby's. Notice to Mariners correction service, ship library setup.",content:'\n      <h2>Printed Charts and Nautical Publications</h2>\n      <p>Safe navigation requires up‑to‑date and accurate charts and publications. As an authorised distributor, Sierra Marine supplies all printed materials your vessel needs. We also offer Notice to Mariners correction services.</p>\n      \n      <h3>Admiralty Printed Products</h3>\n      <ul>\n        <li><strong>Standard Nautical Charts (SNC):</strong> Official charts covering the world\'s oceans and seas. Over 3500 different charts.</li>\n        <li><strong>Planning Charts:</strong> Small‑scale charts for route planning (1:3,500,000 and above).</li>\n        <li><strong>Port Approach Guides:</strong> Detailed information for entering specific ports, depths, marks.</li>\n        <li><strong>Admiralty Sailing Directions (Pilot Books):</strong> Navigation instructions, port descriptions, currents and tides for various regions. More than 70 volumes.</li>\n        <li><strong>List of Lights and Fog Signals:</strong> Lighthouses, buoys, fog signals and other aids to navigation (10 volumes).</li>\n        <li><strong>List of Radio Signals:</strong> Radio stations, DSC, NAVTEX, GMDSS information (6 volumes).</li>\n        <li><strong>Tide Tables:</strong> Tidal heights and currents for primary and secondary ports (4 volumes).</li>\n        <li><strong>Nautical Almanac:</strong> Celestial navigation data, star charts.</li>\n      </ul>\n      \n      <h3>Other Publications</h3>\n      <ul>\n        <li><strong>Turkish charts and nautical publications:</strong> Official charts and guides for Turkish waters.</li>\n        <li><strong>IMO publications:</strong> Current texts of SOLAS, MARPOL, STCW, COLREG, ISPS Code, FSS Code, IBC Code, etc.</li>\n        <li><strong>ITU publications:</strong> Radio regulations, maritime vocabulary, international telecommunications rules.</li>\n        <li><strong>Witherby\'s publications:</strong> Maritime training materials, handbooks, cargo handling guides, LNG/LPG manuals.</li>\n      </ul>\n      \n      <h3>Ship Library Setup</h3>\n      <p>We identify the complete list of mandatory publications for your vessel and create a comprehensive ship library. Regular Notice to Mariners tracking keeps your publications always current. We can also provide software support for digital library management.</p>\n      \n      <img src="/services/printed-charts.png" alt="Admiralty Printed Charts" class="w-full rounded-lg my-4" />\n    ',icon:"\uD83D\uDDFA️",image:"/services/printed-charts.png"},{slug:"survey-hazirligi",title:"Survey Preparation",excerpt:"Identification and supply of missing items before class, flag or PSC inspections.",description:"Pre‑survey checklist, fast supply, marking, documentation support, accredited service network.",content:'\n      <h2>Survey Preparation Services</h2>\n      <p>Before class, flag state or port state control (PSC) inspections, we carry out a comprehensive preparation process to ensure your vessel is fully compliant. Avoid delays and penalties due to unexpected deficiencies.</p>\n      \n      <h3>Survey Preparation Steps</h3>\n      <ul>\n        <li><strong>Gap Analysis:</strong> Our experts inspect your vessel and list missing items: charts, publications, safety equipment, fire systems, pipe markings, first aid supplies, etc.</li>\n        <li><strong>Needs List and Quotation:</strong> We provide a clear list of urgently needed products and offer competitive quotations.</li>\n        <li><strong>Fast Supply:</strong> We deliver missing items from our stock or through our emergency supply channels (24-48 hours across Turkey).</li>\n        <li><strong>Documentation Support:</strong> We help prepare certificates, maintenance records, training documents and up‑to‑date chart/publication lists.</li>\n        <li><strong>Marking and Labelling:</strong> We apply ISO and IMO standard markings for pipes, ventilation ducts, fire equipment, emergency equipment (colour codes, flow arrows, hazard pictograms).</li>\n        <li><strong>Fire and safety equipment periodic maintenance:</strong> Life rafts, fire extinguishers, fixed fire systems, EPIRB, SART servicing and certification through our authorised service centres.</li>\n      </ul>\n      \n      <p>After the survey, our follow‑up and renewal services keep your vessel always ready. <strong>A planned maintenance and renewal approach prevents costly surprises.</strong></p>\n      \n      <img src="/services/markings.png" alt="Pipe Markings" class="w-full rounded-lg my-4" />\n      <img src="/services/posters.png" alt="Warning Posters" class="w-full rounded-lg my-4" />\n      <p><strong>Contact us before your next survey – we will make sure you are fully compliant and documented.</strong></p>\n    ',icon:"\uD83D\uDCCB",image:"/services/markings.png"},{slug:"dijital-yayinlar",title:"Digital Publications & Charts",excerpt:"AVCS, ADP, ENP digital navigation publications and chart services.",description:"In partnership with Elcome LLC, the world's most up‑to‑date digital navigation products. ECDIS integration, user training, 24/7 technical support.",content:'\n      <h2>Digital Navigation Solutions</h2>\n      <p>Digital solutions offer currency, storage convenience and cost savings. As a sub‑distributor of <strong>Elcome LLC</strong>, Sierra Marine provides Admiralty and other leading brands\' digital products.</p>\n      \n      <h3>Our Digital Portfolio</h3>\n      <ul>\n        <li><strong>AVCS (Admiralty Vector Chart Service):</strong> ECDIS‑compatible, continuously updated vector charts covering all world waters. <strong>Weekly updates</strong>. Used on over 20,000 ships worldwide.</li>\n        <li><strong>ADP (Admiralty Digital Publications):</strong> Digital navigation publications (Sailing Directions, List of Lights, List of Radio Signals, Tide Tables, Nautical Almanac). One interface, instant updates. Up to 70% cost savings compared to paper.</li>\n        <li><strong>ENP (Electronic Nautical Publications):</strong> Electronic versions of IMO, ITU and other official publications. Digital signature for legal validity.</li>\n        <li><strong>ARCS (Admiralty Raster Chart Service):</strong> Raster charts, bringing traditional chart appearance to digital environment. Compatible with ECDIS and ECS.</li>\n        <li><strong>IMO, ITU, Witherby\'s digital publications:</strong> Current electronic versions of international regulations and guides (PDF, ePub, XML).</li>\n      </ul>\n      \n      <h3>Advantages</h3>\n      <ul>\n        <li>24/7 up‑to‑date charts and publications – no manual corrections.</li>\n        <li>Single license usable across your entire fleet.</li>\n        <li>User‑friendly interfaces, fast search and filtering.</li>\n        <li>Easy backup and portability (USB, DVD or cloud).</li>\n        <li>Full ECDIS integration – API support.</li>\n      </ul>\n      \n      <h3>Training and Support</h3>\n      <p>We provide installation, user training and technical support for digital navigation products, including ECDIS integration. On‑site or remote training options available.</p>\n      \n      <img src="/services/printed-charts.png" alt="Digital Publications" class="w-full rounded-lg my-4" />\n      <p><strong>Ready for digital transformation? Contact us to create the best package for you.</strong></p>\n    ',icon:"\uD83C\uDF10",image:"/services/printed-charts.png"},{slug:"filo-yonetim",title:"Fleet Management Support",excerpt:"Tracking vessel publications and equipment status, renewal planning and reporting.",description:"Digital tracking system, automatic reminders, custom reports, procurement order management.",content:'\n      <h2>Fleet Management Support</h2>\n      <p>Track your entire fleet\'s documentation, equipment cycles and survey dates digitally. Sierra Marine\'s custom web‑based management system reduces your operational burden and keeps you always ready for inspections.</p>\n      \n      <h3>Our Services</h3>\n      <ul>\n        <li><strong>Central tracking of chart and publication lists:</strong> Maintains current lists for each vessel, automatically reports missing items and updates needed. Integrated Notice to Mariners tracking.</li>\n        <li><strong>Safety equipment renewal reminders:</strong> Tracks life rafts, fire extinguishers, EPIRB, SART, emergency batteries, hydrostatic releases, etc., sends email/SMS alerts before expiry.</li>\n        <li><strong>Management of class, flag and PSC deficiency reports:</strong> Enter survey results, assign corrective actions, monitor completion status. Historical deficiency analysis.</li>\n        <li><strong>Vessel‑specific requirement lists and procurement orders:</strong> Create needs lists per vessel, place orders with one click. Order status tracking.</li>\n        <li><strong>Reporting:</strong> Customised reports (PDF, Excel, CSV) on fleet status, compliance rates, upcoming surveys, most common deficiencies.</li>\n        <li><strong>Ship library audit:</strong> Periodically checks the currency of publications on your vessels, identifies missing items and ensures completion.</li>\n      </ul>\n      \n      <h3>Why Fleet Management Support?</h3>\n      <ul>\n        <li><strong>Time and labour savings:</strong> Eliminate manual tracking.</li>\n        <li><strong>Minimised risk of inspection failures:</strong> Always be ready.</li>\n        <li><strong>Reduced operational costs:</strong> Prevent delays and penalties due to deficiencies.</li>\n        <li><strong>Centralised control:</strong> Manage your entire fleet from one panel.</li>\n      </ul>\n      \n      <img src="/services/office.png" alt="Office Management" class="w-full rounded-lg my-4" />\n      <p>Our system is web‑based, accessible from anywhere, no additional software installation required. <strong>Request a demo – contact us today.</strong></p>\n    ',icon:"⚓",image:"/services/office.png"}]}},7648:function(i,e,n){n.d(e,{default:function(){return r.a}});var a=n(2972),r=n.n(a)},9376:function(i,e,n){var a=n(5475);n.o(a,"usePathname")&&n.d(e,{usePathname:function(){return a.usePathname}})}}]);